#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <algorithm>
#include <vector>

// Configuration
#define BUFFER_SIZE_GB 3.0f
#define NUM_WARMUP 5
#define NUM_TIMED 20
#define THREADS_PER_BLOCK 256
#define ELEMENTS_PER_THREAD 64  // Each thread reads this many float4 elements

typedef float4 vec_t;

__global__ void readBandwidthKernel(const vec_t* __restrict__ input,
                                     float* __restrict__ sink,
                                     size_t num_elements,
                                     int iterations) {
    size_t idx = blockIdx.x * blockDim.x + threadIdx.x;
    size_t stride = blockDim.x * gridDim.x;

    float acc = 0.0f;

    // Grid-stride loop for multiple iterations
    for (int iter = 0; iter < iterations; iter++) {
        size_t base_idx = idx;
        while (base_idx < num_elements) {
            // Read multiple elements per thread
            #pragma unroll
            for (int i = 0; i < ELEMENTS_PER_THREAD; i++) {
                size_t read_idx = base_idx + i * stride;
                if (read_idx < num_elements) {
                    vec_t val = input[read_idx];
                    acc += val.x + val.y + val.z + val.w;
                }
            }
            base_idx += stride * ELEMENTS_PER_THREAD;
        }
    }

    // Sink the accumulator to prevent dead-code elimination
    // Use atomic to ensure the write happens (prevents compiler from optimizing away)
    if (idx == 0) {
        *sink = acc;
    }
}

double measureKernel(const vec_t* d_input, float* d_sink,
                     size_t num_elements, int iterations,
                     hipStream_t stream) {
    hipEvent_t start, stop;
    hipEventCreate(&start);
    hipEventCreate(&stop);

    int blocks = 1024;  // Enough blocks to saturate GPU

    hipEventRecord(start, stream);
    readBandwidthKernel<<<blocks, THREADS_PER_BLOCK, 0, stream>>>(
        d_input, d_sink, num_elements, iterations);
    hipEventRecord(stop, stream);

    hipEventSynchronize(stop);

    float elapsed_ms;
    hipEventElapsedTime(&elapsed_ms, start, stop);

    hipEventDestroy(start);
    hipEventDestroy(stop);

    return elapsed_ms / 1000.0;  // Convert to seconds
}

int main() {
    // Set device
    hipSetDevice(0);

    // Calculate buffer size
    size_t buffer_bytes = (size_t)(BUFFER_SIZE_GB * 1024 * 1024 * 1024);
    // Align to float4 boundary (16 bytes)
    buffer_bytes = (buffer_bytes / 16) * 16;

    size_t num_elements = buffer_bytes / sizeof(vec_t);

    printf("Buffer size: %.2f GB (%zu bytes)\n",
           (double)buffer_bytes / (1024.0 * 1024.0 * 1024.0), buffer_bytes);
    printf("Number of float4 elements: %zu\n", num_elements);

    // Allocate device memory
    vec_t* d_input;
    float* d_sink;
    hipMalloc(&d_input, buffer_bytes);
    hipMalloc(&d_sink, sizeof(float));

    // Initialize input data
    std::vector<vec_t> h_input(num_elements);
    for (size_t i = 0; i < num_elements; i++) {
        h_input[i] = make_float4(1.0f, 2.0f, 3.0f, 4.0f);
    }
    hipMemcpy(d_input, h_input.data(), buffer_bytes, hipMemcpyHostToDevice);

    // Create stream
    hipStream_t stream;
    hipStreamCreate(&stream);

    // Warmup runs
    printf("Running %d warmup iterations...\n", NUM_WARMUP);
    for (int i = 0; i < NUM_WARMUP; i++) {
        readBandwidthKernel<<<1024, THREADS_PER_BLOCK, 0, stream>>>(
            d_input, d_sink, num_elements, 1);
    }
    hipStreamSynchronize(stream);

    // Timed runs
    printf("Running %d timed iterations...\n", NUM_TIMED);
    std::vector<double> times(NUM_TIMED);

    for (int i = 0; i < NUM_TIMED; i++) {
        times[i] = measureKernel(d_input, d_sink, num_elements, 1, stream);
