#define NUM_WARMUP 3
#define NUM_TIMED 15
#define THREADS_PER_BLOCK 256
#define NUM_BLOCKS 2048  // Enough to saturate GPU
#define READ_ITERATIONS 8  // Number of full passes over the data

typedef float4 vec_t;

// Simple atomic add for float
__device__ inline void atomicAddFloat(float* addr, float val) {
    unsigned int* addr_as_uint = (unsigned int*)addr;
    unsigned int old = *addr_as_uint, assumed;
    do {
        assumed = old;
        float sum = __uint_as_float(assumed) + val;
        old = atomicCAS(addr_as_uint, assumed, __float_as_uint(sum));
    } while (assumed != old);
}

__global__ void readBandwidthKernel(const vec_t* __restrict__ input,
                                     float* __restrict__ output,
                                     size_t num_elements) {
    size_t tid = blockIdx.x * blockDim.x + threadIdx.x;
    size_t total_threads = blockDim.x * gridDim.x;

    float acc = 0.0f;

    // Each thread does multiple full passes to ensure memory traffic
    for (int pass = 0; pass < READ_ITERATIONS; pass++) {
        // Grid-stride loop
        for (size_t idx = tid; idx < num_elements; idx += total_threads) {
            // Vectorized load
            vec_t val = input[idx];
            acc += val.x + val.y + val.z + val.w;
        }
    }

    // Reduce within block
    __shared__ float shared_acc[256];
    shared_acc[threadIdx.x] = acc;
    __syncthreads();

    // Tree reduction
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (threadIdx.x < stride) {
            shared_acc[threadIdx.x] += shared_acc[threadIdx.x + stride];
        }
        __syncthreads();
    }

    // Write block result to global output
    if (threadIdx.x == 0) {
        atomicAddFloat(output, shared_acc[0]);
    }
}

