    size_t total_threads = blockDim.x * gridDim.x;

    float acc = 0.0f;

    // Each thread reads 4 consecutive float4 elements for better ILP
    for (size_t base_idx = tid * 4; base_idx < num_elements; base_idx += total_threads * 4) {
        #pragma unroll 4
        for (int i = 0; i < 4; i++) {
            vec_t val = input[base_idx + i];
            acc += val.x + val.y + val.z + val.w;
        }
    }

    // Block reduction
    __shared__ float shared[256];
    shared[threadIdx.x] = acc;
    __syncthreads();

    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (threadIdx.x < stride) {
            shared[threadIdx.x] += shared[threadIdx.x + stride];
        }
        __syncthreads();
    }

    if (threadIdx.x == 0) {
        output[blockIdx.x] = shared[0];
    }
}

__global__ void reduceKernel(const float* input, float* output, int n) {
    float acc = 0.0f;
    for (int i = threadIdx.x; i < n; i += blockDim.x) {
        acc += input[i];
    }

    __shared__ float shared[256];
    shared[threadIdx.x] = acc;
    __syncthreads();

    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (threadIdx.x < stride) {
            shared[threadIdx.x] += shared[threadIdx.x + stride];
        }
        __syncthreads();
    }

    if (threadIdx.x == 0) {
        *output = shared[0];
    }
}

double measureKernel(const vec_t* d_input, float* d_block_out, float* d_final,
                     size_t num_elements, hipStream_t stream) {
    hipEvent_t start, stop;
    hipEventCreate(&start);
    hipEventCreate(&stop);

    hipEventRecord(start, stream);

    // Single dispatch of the main read kernel
    readBandwidthKernel<<<NUM_BLOCKS, THREADS_PER_BLOCK, 0, stream>>>(
        d_input, d_block_out, num_elements);

    // Reduction kernel (minimal overhead)
    reduceKernel<<<1, THREADS_PER_BLOCK, 0, stream>>>(
        d_block_out, d_final, NUM_BLOCKS);

    hipEventRecord(stop, stream);
    hipEventSynchronize(stop);

    float elapsed_ms;
    hipEventElapsedTime(&elapsed_ms, start, stop);

    hipEventDestroy(start);
    hipEventDestroy(stop);

    return elapsed_ms / 1000.0;
}

int main() {
    hipSetDevice(0);

    // 3GB buffer aligned to float4 (16 bytes)
    size_t buffer_bytes = (size_t)(BUFFER_SIZE_GB * 1024 * 1024 * 1024);
    buffer_bytes = (buffer_bytes / 16) * 16;

    size_t num_elements = buffer_bytes / sizeof(vec_t);

    printf("Buffer size: %.2f GB (%zu bytes)\n",
           (double)buffer_bytes / (1024.0 * 1024.0 * 1024.0), buffer_bytes);
    printf("Number of float4 elements: %zu\n", num_elements);
    printf("Total threads: %d blocks x %d threads = %d\n",
           NUM_BLOCKS, THREADS_PER_BLOCK, NUM_BLOCKS * THREADS_PER_BLOCK);

    // Allocate device memory
    vec_t* d_input;
    float *d_block_out, *d_final;

    hipMalloc(&d_input, buffer_bytes);
    hipMalloc(&d_block_out, NUM_BLOCKS * sizeof(float));
    hipMalloc(&d_final, sizeof(float));

    // Initialize with varying data to prevent any caching/compression optimizations
    std::vector<vec_t> h_input(num_elements);
    for (size_t i = 0; i < num_elements; i++) {
        h_input[i] = make_float4(
            (float)((i * 17) % 100000),
            (float)((i * 31) % 100000),
            (float)((i * 43) % 100000),
            (float)((i * 59) % 100000)
        );
    }
    printf("Copying data to GPU...\n");
    hipMemcpy(d_input, h_input.data(), buffer_bytes, hipMemcpyHostToDevice);

    hipStream_t stream;
    hipStreamCreate(&stream);

    // Warmup runs
    printf("Running %d warmup iterations...\n", NUM_WARMUP);
    for (int i = 0; i < NUM_WARMUP; i++) {
        readBandwidthKernel<<<NUM_BLOCKS, THREADS_PER_BLOCK, 0, stream>>>(
            d_input, d_block_out, num_elements);
        reduceKernel<<<1, THREADS_PER_BLOCK, 0, stream>>>(
            d_block_out, d_final, NUM_BLOCKS);
    }
    hipStreamSynchronize(stream);

    // Timed runs
    printf("Running %d timed iterations...\n", NUM_TIMED);
    std::vector<double> times(NUM_TIMED);

    for (int i = 0; i < NUM_TIMED; i++) {
        times[i] = measureKernel(d_input, d_block_out, d_final, num_elements, stream);
    }

    // Sort and get median
    std::sort(times.begin(), times.end());
    double median_time = times[NUM_TIMED / 2];

    // Bandwidth = buffer_bytes / time (single pass read)
    double bandwidth_gbps = (double)buffer_bytes / median_time / (1024.0 * 1024.0 * 1024.0);

    printf("\n=== Results ===\n");
    printf("Median kernel time: %.4f ms\n", median_time * 1000.0);
    printf("HBM Read Bandwidth: %.2f GB/s\n", bandwidth_gbps);

    // Output in required format for grader
    printf("\nHBM_BANDWIDTH_GBPS=%.2f\n", bandwidth_gbps);
    printf("buffer_bytes=%zu\n", buffer_bytes);

    // Verify the computation actually happened
    float h_final;
    hipMemcpy(&h_final, d_final, sizeof(float), hipMemcpyDeviceToHost);
    printf("Verification sum: %.0f\n", h_final);

    hipFree(d_input);
    hipFree(d_block_out);
    hipFree(d_final);
    hipStreamDestroy(stream);

    return 0;
}

